    /**
     */
    protected open fun paintBeamHelper(cx: Double, 
    cy: Double, 
    canvas: com.omnifret.gplayer.platform.ICanvas, 
    h: com.omnifret.gplayer.rendering.utils.BeamingHelper, 
    flagsElement: com.omnifret.gplayer.model.BeatSubElement, 
    beamsElement: com.omnifret.gplayer.model.BeatSubElement): Unit{
        canvas.color = if(h.voice!!.index == 0.0)  this.resources.mainGlyphColor else this.resources.secondaryGlyphColor
