     */
    protected abstract fun getFlagTopY(beat: com.omnifret.gplayer.model.Beat, direction: com.omnifret.gplayer.rendering.utils.BeamDirection): Double
    
    /**
     */
    protected abstract fun getFlagBottomY(beat: com.omnifret.gplayer.model.Beat, direction: com.omnifret.gplayer.rendering.utils.BeamDirection): Double
    
    /**
     */
    protected open fun shouldPaintFlag(beat: com.omnifret.gplayer.model.Beat): Boolean{
        if (beat.graceType == com.omnifret.gplayer.model.GraceType.BendGrace)
        {
            return false
        }
        if (beat.deadSlapped)
        {
            return false
        }
        if (beat.graceType != com.omnifret.gplayer.model.GraceType.None && this.settings.notation.notationMode == com.omnifret.gplayer.NotationMode.SongBook)
        {
            return false
        }
        if (beat.duration == com.omnifret.gplayer.model.Duration.Whole || beat.duration == com.omnifret.gplayer.model.Duration.DoubleWhole || beat.duration == com.omnifret.gplayer.model.Duration.QuadrupleWhole)
        {
            return false
        }
        return true
    }
    
    /**
     */
    protected open fun paintFlag(cx: Double, cy: Double, canvas: com.omnifret.gplayer.platform.ICanvas, h: com.omnifret.gplayer.rendering.utils.BeamingHelper, flagsElement: com.omnifret.gplayer.model.BeatSubElement): Unit{
        for (beat in h.beats)
        {
            if (!this.shouldPaintFlag(beat))
            {
                continue
            }
            var isGrace: Boolean = beat.graceType != com.omnifret.gplayer.model.GraceType.None
            var beatLineX: Double = this.getBeatX(beat, com.omnifret.gplayer.rendering.BeatXPosition.Stem)
            var direction: com.omnifret.gplayer.rendering.utils.BeamDirection = this.getBeamDirection(h)
            var topY: Double = cy + this.y + this.getFlagTopY(beat, direction)
            var bottomY: Double = cy + this.y + this.getFlagBottomY(beat, direction)
            var flagY: Double = 0.0
            if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Down)
            {
                flagY = bottomY
            }
            else 
            {
                flagY = topY
            }
            if (!h.hasStem(true, beat))
            {
                continue
            }
            this.paintBeamingStem(
                beat
                , 
                cy + this.y
                , 
                cx + this.x + beatLineX
                , 
                topY
                , 
                bottomY
                , 
                canvas
            
            )
            (com.omnifret.gplayer.rendering.utils.ElementStyleHelper.beat(canvas, flagsElement, beat))
            .use {
                var flagWidth: Double = 0.0
                if (h.hasFlag(true, beat))
                {
                    var glyph: com.omnifret.gplayer.rendering.glyphs.FlagGlyph = com.omnifret.gplayer.rendering.glyphs.FlagGlyph(cx + this.x + beatLineX, flagY, beat.duration, direction, isGrace)
                    glyph.renderer = this
                    glyph.doLayout()
                    glyph.paint(0.0, 0.0, canvas)
                    flagWidth = glyph.width / (2.0).toDouble()
                }
                if (beat.graceType == com.omnifret.gplayer.model.GraceType.BeforeBeat)
                {
                    if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Down)
                    {
                        com.omnifret.gplayer.platform.CanvasHelper.fillMusicFontSymbolSafe(
                            canvas
                            , 
                            cx + this.x + beatLineX + flagWidth / (2.0).toDouble()
                            , 
                            (topY + bottomY - this.smuflMetrics.glyphHeights.get(com.omnifret.gplayer.model.MusicFontSymbol.GraceNoteSlashStemDown)!!) / (2.0).toDouble()
                            , 
                            com.omnifret.gplayer.EngravingSettings.GraceScale
                            , 
                            com.omnifret.gplayer.model.MusicFontSymbol.GraceNoteSlashStemDown
                            , 
                            true
                        
                        )
                    }
                    else 
                    {
                        com.omnifret.gplayer.platform.CanvasHelper.fillMusicFontSymbolSafe(
                            canvas
                            , 
                            cx + this.x + beatLineX + flagWidth / (2.0).toDouble()
                            , 
                            (topY + bottomY + this.smuflMetrics.glyphHeights.get(com.omnifret.gplayer.model.MusicFontSymbol.GraceNoteSlashStemUp)!!) / (2.0).toDouble()
                            , 
                            com.omnifret.gplayer.EngravingSettings.GraceScale
                            , 
                            com.omnifret.gplayer.model.MusicFontSymbol.GraceNoteSlashStemUp
                            , 
                            true
                        
                        )
                    }
                }
            }
        }
    }
    
