    protected override fun createPreBeatGlyphs(): Unit{
        super.createPreBeatGlyphs()
        this.addPreBeatGlyph(com.omnifret.gplayer.rendering.glyphs.BarLineGlyph(false, this.bar.staff.track.score.stylesheet.extendBarLines))
        this.createLinePreBeatGlyphs()
        var hasSpaceAfterStartGlyphs: Boolean = false
