        }
        if (this.shouldCreateBarNumber())
        {
            this.addPreBeatGlyph(com.omnifret.gplayer.rendering.glyphs.BarNumberGlyph(0.0, this.getLineHeight(-0.5), this.bar.index + 1.0))
        }
        else if (!hasSpaceAfterStartGlyphs)
