    public fun shouldCreateBarNumber(): Boolean{
        var display: com.omnifret.gplayer.model.BarNumberDisplay = com.omnifret.gplayer.model.BarNumberDisplay.AllBars
        if (!this.settings.notation.isNotationElementVisible(com.omnifret.gplayer.NotationElement.BarNumber))
        {
            display = com.omnifret.gplayer.model.BarNumberDisplay.Hide
        }
        else if (this.bar.barNumberDisplay != null)
        {
            display = this.bar.barNumberDisplay!!
        }
        else 
        {
            display = this.bar.staff.track.score.stylesheet.barNumberDisplay
        }
        when (display)
        {
            com.omnifret.gplayer.model.BarNumberDisplay.AllBars -> 
            {
                return true
            }
            com.omnifret.gplayer.model.BarNumberDisplay.FirstOfSystem -> 
            {
                return this.isFirstOfStaff
            }
            com.omnifret.gplayer.model.BarNumberDisplay.Hide -> 
            {
                return false
            }
            else -> { }
        }
        return true
    }
    
