        this.addPostBeatGlyph(com.omnifret.gplayer.rendering.glyphs.BarLineGlyph(true, this.bar.staff.track.score.stylesheet.extendBarLines))
        if (lastBar.masterBar.isRepeatEnd && lastBar.masterBar.repeatCount > 2 && this.settings.notation.isNotationElementVisible(com.omnifret.gplayer.NotationElement.RepeatCount))
        {
