    /**
     */
    protected open fun paintBar(cx: Double, cy: Double, canvas: com.omnifret.gplayer.platform.ICanvas, h: com.omnifret.gplayer.rendering.utils.BeamingHelper, beamsElement: com.omnifret.gplayer.model.BeatSubElement): Unit{
        var direction: com.omnifret.gplayer.rendering.utils.BeamDirection = this.getBeamDirection(h)
        var isGrace: Boolean = h.graceType != com.omnifret.gplayer.model.GraceType.None
        var scaleMod: Double = if(isGrace)  com.omnifret.gplayer.EngravingSettings.GraceScale else 1.0
        var barSpacing: Double = (this.beamSpacing + this.beamThickness) * scaleMod
        var barSize: Double = this.beamThickness * scaleMod
        if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Down)
        {
            barSpacing = -barSpacing
            barSize = -barSize
        }
        if (true) {
            var i: Double = 0.0
            var j: Double = h.beats.length
            
            while(i < j){
                var beat: com.omnifret.gplayer.model.Beat = h.beats[(i).toInt()]
                if (beat.deadSlapped)
                {
                    i++
                    continue
                }
                var stemX: Double = this.getBeatX(beat, com.omnifret.gplayer.rendering.BeatXPosition.Stem)
                var y1: Double = cy + this.y
                if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)
                {
                    y1 += this.getFlagBottomY(beat, direction)
                }
                else 
                {
                    y1 += this.getFlagTopY(beat, direction)
                }
                var y2: Double = cy + this.y + this.calculateBeamY(h, stemX)
                var stemY1: Double
                var stemY2: Double
                if (y1 < y2)
                {
                    stemY1 = y1
                    stemY2 = y2
                }
                else 
                {
                    stemY1 = y2
                    stemY2 = y1
                }
                this.paintBeamingStem(
                    beat
                    , 
                    cy + this.y
                    , 
                    cx + this.x + stemX
                    , 
                    stemY1
                    , 
                    stemY2
                    , 
                    canvas
                
                )
                (com.omnifret.gplayer.rendering.utils.ElementStyleHelper.beat(canvas, beamsElement, beat))
                .use {
                    var brokenBarOffset: Double = this.smuflMetrics.brokenBeamWidth * scaleMod
                    var barCount: Double = com.omnifret.gplayer.model.ModelUtils.getIndex(beat.duration) - (2.0).toDouble()
                    var barStart: Double = cy + this.y
                    var stemThickness: Double = this.smuflMetrics.stemThickness
                    if (true) {
                        var barIndex: Double = 0.0
                        
                        while(barIndex < barCount){
                            var barStartX: Double = com.omnifret.gplayer.core.ecmaScript.Math.floor(stemX + stemThickness)
                            var barEndX: Double = 0.0
                            var barStartY: Double = 0.0
                            var barEndY: Double = 0.0
                            var barY: Double = barStart + barIndex * barSpacing
                            if (i < h.beats.length - (1.0).toDouble())
                            {
                                var isFullBarJoin: Boolean = com.omnifret.gplayer.rendering.utils.BeamingHelper.isFullBarJoin(beat, h.beats[(i + 1.0).toInt()], barIndex)
                                if (barIndex == barCount - (1.0).toDouble() && isFullBarJoin && beat.beamingMode == com.omnifret.gplayer.model.BeatBeamingMode.ForceSplitOnSecondaryToNext)
                                {
                                    barEndX = com.omnifret.gplayer.core.ecmaScript.Math.ceil(barStartX + brokenBarOffset)
                                    barStartY = barY + this.calculateBeamY(h, barStartX)
                                    barEndY = barY + this.calculateBeamY(h, barEndX)
                                    com.omnifret.gplayer.rendering.LineBarRenderer.paintSingleBar(
                                        canvas
                                        , 
                                        cx + this.x + barStartX
                                        , 
                                        barStartY
                                        , 
                                        cx + this.x + barEndX
                                        , 
                                        barEndY
                                        , 
                                        barSize
                                    
                                    )
                                    barEndX = com.omnifret.gplayer.core.ecmaScript.Math.floor(this.getBeatX(h.beats[(i + 1.0).toInt()], com.omnifret.gplayer.rendering.BeatXPosition.Stem))
                                    barStartX = com.omnifret.gplayer.core.ecmaScript.Math.floor(barEndX - brokenBarOffset)
                                    barStartY = barY + this.calculateBeamY(h, barStartX)
                                    barEndY = barY + this.calculateBeamY(h, barEndX)
                                    com.omnifret.gplayer.rendering.LineBarRenderer.paintSingleBar(
                                        canvas
                                        , 
                                        cx + this.x + barStartX
                                        , 
                                        barStartY
                                        , 
                                        cx + this.x + barEndX
                                        , 
                                        barEndY
                                        , 
                                        barSize
                                    
                                    )
                                }
                                else 
                                {
                                    if (isFullBarJoin)
                                    {
                                        barEndX = com.omnifret.gplayer.core.ecmaScript.Math.ceil(this.getBeatX(h.beats[(i + 1.0).toInt()], com.omnifret.gplayer.rendering.BeatXPosition.Stem))
                                    }
                                    else if (i == 0.0 || !com.omnifret.gplayer.rendering.utils.BeamingHelper.isFullBarJoin(h.beats[(i - (1.0).toDouble()).toInt()], beat, barIndex))
                                    {
                                        barEndX = com.omnifret.gplayer.core.ecmaScript.Math.ceil(barStartX + brokenBarOffset)
                                    }
                                    else 
                                    {
                                        barIndex++
                                        continue
                                    }
                                    barStartY = barY + this.calculateBeamY(h, barStartX)
                                    barEndY = barY + this.calculateBeamY(h, barEndX)
                                    com.omnifret.gplayer.rendering.LineBarRenderer.paintSingleBar(
                                        canvas
                                        , 
                                        cx + this.x + barStartX
                                        , 
                                        barStartY
                                        , 
                                        cx + this.x + barEndX
                                        , 
                                        barEndY
                                        , 
                                        barSize
                                    
                                    )
                                }
                            }
                            else if (i > 0 && !com.omnifret.gplayer.rendering.utils.BeamingHelper.isFullBarJoin(beat, h.beats[(i - (1.0).toDouble()).toInt()], barIndex))
                            {
                                barEndX = com.omnifret.gplayer.core.ecmaScript.Math.ceil(stemX)
                                barStartX = com.omnifret.gplayer.core.ecmaScript.Math.floor(stemX - brokenBarOffset)
                                barStartY = barY + this.calculateBeamY(h, barStartX)
                                barEndY = barY + this.calculateBeamY(h, barEndX)
                                com.omnifret.gplayer.rendering.LineBarRenderer.paintSingleBar(
                                    canvas
                                    , 
                                    cx + this.x + barStartX
                                    , 
                                    barStartY
                                    , 
                                    cx + this.x + barEndX
                                    , 
                                    barEndY
                                    , 
                                    barSize
                                
                                )
                            }
                            barIndex++
                        }
                    }
                    i++
                }
            }
        }
        if (h.graceType == com.omnifret.gplayer.model.GraceType.BeforeBeat)
        {
            var beatLineX: Double = this.getBeatX(h.beats[(0).toInt()], com.omnifret.gplayer.rendering.BeatXPosition.Stem)
            var flagWidth: Double = this.smuflMetrics.glyphWidths.get(com.omnifret.gplayer.model.MusicFontSymbol.Flag8thUp)!! * com.omnifret.gplayer.EngravingSettings.GraceScale
            var slashY: Double = (((cy + this.y + this.calculateBeamY(h, beatLineX))).toInt() or 0).toDouble()
            slashY += barSize + barSpacing
            if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Down)
            {
                com.omnifret.gplayer.platform.CanvasHelper.fillMusicFontSymbolSafe(
                    canvas
                    , 
                    cx + this.x + beatLineX + flagWidth / (2.0).toDouble()
                    , 
                    slashY
                    , 
                    com.omnifret.gplayer.EngravingSettings.GraceScale
                    , 
                    com.omnifret.gplayer.model.MusicFontSymbol.GraceNoteSlashStemDown
                    , 
                    true
                
                )
            }
            else 
            {
                com.omnifret.gplayer.platform.CanvasHelper.fillMusicFontSymbolSafe(
                    canvas
                    , 
                    cx + this.x + beatLineX + flagWidth / (2.0).toDouble()
                    , 
                    slashY
                    , 
                    com.omnifret.gplayer.EngravingSettings.GraceScale
                    , 
                    com.omnifret.gplayer.model.MusicFontSymbol.GraceNoteSlashStemUp
                    , 
                    true
                
                )
            }
        }
    }
    
    /**
     */
    protected fun calculateBeamingOverflows(rendererTop: Double, rendererBottom: Double): Unit{
        var maxNoteY: Double = 0.0
        var minNoteY: Double = 0.0
        for (v in this.helpers.beamHelpers)
        {
            for (h in v)
            {
                if (!this.shouldPaintBeamingHelper(h))
                {
                    if (h.hasTuplet && h.isRestBeamHelper)
                    {
                        var tupletGroup: com.omnifret.gplayer.model.TupletGroup = h.beats[(0).toInt()].tupletGroup!!
                        var tupletFirst: com.omnifret.gplayer.model.Beat = tupletGroup.beats[(0).toInt()]
                        var tupletLast: com.omnifret.gplayer.model.Beat = tupletGroup.beats[(tupletGroup.beats.length - (1.0).toDouble()).toInt()]
                        var tupletDirection: com.omnifret.gplayer.rendering.utils.BeamDirection = this.getTupletBeamDirection(h)
                        if (tupletDirection == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)
                        {
                            var restTop: Double = com.omnifret.gplayer.core.ecmaScript.Math.min(this.getRestY(tupletFirst, com.omnifret.gplayer.rendering.NoteYPosition.Top), this.getRestY(tupletLast, com.omnifret.gplayer.rendering.NoteYPosition.Top))
                            var topY: Double = restTop - this.tupletSize - this.tupletOffset
                            if (topY < maxNoteY)
                            {
                                maxNoteY = topY
                            }
                        }
                        else 
                        {
                            var restBottom: Double = com.omnifret.gplayer.core.ecmaScript.Math.max(this.getRestY(tupletFirst, com.omnifret.gplayer.rendering.NoteYPosition.Bottom), this.getRestY(tupletLast, com.omnifret.gplayer.rendering.NoteYPosition.Bottom))
                            var bottomY: Double = restBottom + this.tupletSize + this.tupletOffset
                            if (bottomY > minNoteY)
                            {
                                minNoteY = bottomY
                            }
                        }
                    }
                }
                else if (h.beats.length == 1.0 && h.beats[(0).toInt()].duration >= com.omnifret.gplayer.model.Duration.Half)
                {
                    var tupletDirection: com.omnifret.gplayer.rendering.utils.BeamDirection = this.getTupletBeamDirection(h)
                    var direction: com.omnifret.gplayer.rendering.utils.BeamDirection = this.getBeamDirection(h)
                    var flagOverflow: Double = this.smuflMetrics.stemFlagOffsets.get(h.beats[(0).toInt()].duration)!!
                    if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)
                    {
                        var topY: Double = this.getFlagTopY(h.beats[(0).toInt()], direction) - flagOverflow
                        if (h.hasTuplet && tupletDirection == ((direction as com.omnifret.gplayer.rendering.utils.BeamDirection)))
                        {
                            topY -= this.tupletSize + this.tupletOffset
                        }
                        if (topY < maxNoteY)
                        {
                            maxNoteY = topY
                        }
                        if (h.hasTuplet && tupletDirection != ((direction as com.omnifret.gplayer.rendering.utils.BeamDirection)))
                        {
                            var bottomY: Double = this.getFlagBottomY(h.beats[(0).toInt()], tupletDirection)
                            bottomY += this.tupletSize + this.tupletOffset
                            if (bottomY > minNoteY)
                            {
                                minNoteY = bottomY
                            }
                        }
                    }
                    else 
                    {
                        var bottomY: Double = this.getFlagBottomY(h.beats[(0).toInt()], direction) + flagOverflow
                        if (h.hasTuplet && tupletDirection == ((direction as com.omnifret.gplayer.rendering.utils.BeamDirection)))
                        {
                            bottomY += this.tupletSize + this.tupletOffset
                        }
                        if (bottomY > minNoteY)
                        {
                            minNoteY = bottomY
                        }
                        if (h.hasTuplet && tupletDirection != ((direction as com.omnifret.gplayer.rendering.utils.BeamDirection)))
                        {
                            var topY: Double = this.getFlagTopY(h.beats[(0).toInt()], tupletDirection)
                            topY -= this.tupletSize + this.tupletOffset
                            if (topY < maxNoteY)
                            {
                                maxNoteY = topY
                            }
                        }
                    }
                }
                else 
                {
                    var direction: com.omnifret.gplayer.rendering.utils.BeamDirection = this.getBeamDirection(h)
                    this.ensureBeamDrawingInfo(h, direction)
                    var drawingInfo: com.omnifret.gplayer.rendering.utils.BeamingHelperDrawInfo = h.drawingInfos.get(direction)!!
                    var tupletDirection: com.omnifret.gplayer.rendering.utils.BeamDirection = this.getTupletBeamDirection(h)
                    if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)
                    {
                        var topY: Double = com.omnifret.gplayer.core.ecmaScript.Math.min(drawingInfo.startY, drawingInfo.endY)
                        if (h.hasTuplet && tupletDirection == ((direction as com.omnifret.gplayer.rendering.utils.BeamDirection)))
                        {
                            topY -= this.tupletSize + this.tupletOffset
                        }
                        if (topY < maxNoteY)
                        {
                            maxNoteY = topY
                        }
                        var bottomY: Double = this.voiceContainer.getLowestNoteY(h.beatOfLowestNote, com.omnifret.gplayer.rendering.NoteYPosition.Bottom)
                        if (h.hasTuplet && tupletDirection != ((direction as com.omnifret.gplayer.rendering.utils.BeamDirection)))
                        {
                            bottomY += this.tupletSize + this.tupletOffset
                        }
                        if (bottomY > minNoteY)
                        {
                            minNoteY = bottomY
                        }
                    }
                    else 
                    {
                        var bottomY: Double = com.omnifret.gplayer.core.ecmaScript.Math.max(drawingInfo.startY, drawingInfo.endY)
                        if (h.hasTuplet && tupletDirection == ((direction as com.omnifret.gplayer.rendering.utils.BeamDirection)))
                        {
                            bottomY += this.tupletSize + this.tupletOffset
                        }
                        if (bottomY > minNoteY)
                        {
                            minNoteY = bottomY
                        }
                        var topY: Double = this.voiceContainer.getHighestNoteY(h.beatOfHighestNote, com.omnifret.gplayer.rendering.NoteYPosition.Top)
                        if (h.hasTuplet && tupletDirection != ((direction as com.omnifret.gplayer.rendering.utils.BeamDirection)))
                        {
                            topY -= this.tupletSize + this.tupletOffset
                        }
                        if (topY < maxNoteY)
                        {
                            maxNoteY = topY
                        }
                    }
                }
            }
        }
        if (maxNoteY < rendererTop)
        {
            this.registerOverflowTop(com.omnifret.gplayer.core.ecmaScript.Math.abs(maxNoteY))
        }
        if (minNoteY > rendererBottom)
        {
            this.registerOverflowBottom(com.omnifret.gplayer.core.ecmaScript.Math.abs(minNoteY) - rendererBottom)
        }
    }
    
    /**
     */
    protected fun initializeBeamDrawingInfo(h: com.omnifret.gplayer.rendering.utils.BeamingHelper, direction: com.omnifret.gplayer.rendering.utils.BeamDirection): com.omnifret.gplayer.rendering.utils.BeamingHelperDrawInfo{
        var drawingInfo: com.omnifret.gplayer.rendering.utils.BeamingHelperDrawInfo = com.omnifret.gplayer.rendering.utils.BeamingHelperDrawInfo()
        var firstBeat: com.omnifret.gplayer.model.Beat = h.beats[(0).toInt()]
        var lastBeat: com.omnifret.gplayer.model.Beat = h.beats[(h.beats.length - (1.0).toDouble()).toInt()]
        drawingInfo.startBeat = firstBeat
        drawingInfo.startX = this.getBeatX(firstBeat, com.omnifret.gplayer.rendering.BeatXPosition.Stem)
        drawingInfo.startY = if(direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)  this.getFlagTopY(firstBeat, direction) else this.getFlagBottomY(firstBeat, direction)
        drawingInfo.endBeat = lastBeat
        drawingInfo.endX = this.getBeatX(lastBeat, com.omnifret.gplayer.rendering.BeatXPosition.Stem)
        drawingInfo.endY = if(direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)  this.getFlagTopY(lastBeat, direction) else this.getFlagBottomY(lastBeat, direction)
        var maxSlope: Double = this.smuflMetrics.oneStaffSpace
        if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Down && drawingInfo.startY > drawingInfo.endY && drawingInfo.startY - drawingInfo.endY > maxSlope)
        {
            drawingInfo.endY = drawingInfo.startY - maxSlope
        }
        if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Down && drawingInfo.endY > drawingInfo.startY && drawingInfo.endY - drawingInfo.startY > maxSlope)
        {
            drawingInfo.startY = drawingInfo.endY - maxSlope
        }
        if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up && drawingInfo.startY < drawingInfo.endY && drawingInfo.endY - drawingInfo.startY > maxSlope)
        {
            drawingInfo.endY = drawingInfo.startY + maxSlope
        }
        if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up && drawingInfo.endY < drawingInfo.startY && drawingInfo.startY - drawingInfo.endY > maxSlope)
        {
            drawingInfo.startY = drawingInfo.endY + maxSlope
        }
        return drawingInfo
    }
    
    protected open val beamSpacing: Double
    get(){
        return this.smuflMetrics.beamSpacing
    }
    
    protected open val beamThickness: Double
    get(){
        return this.smuflMetrics.beamThickness
    }
    
    /**
     */
    protected fun ensureBeamDrawingInfo(h: com.omnifret.gplayer.rendering.utils.BeamingHelper, direction: com.omnifret.gplayer.rendering.utils.BeamDirection): Unit{
        if (h.drawingInfos.has(direction))
        {
            return
        }
        var drawingInfo: com.omnifret.gplayer.rendering.utils.BeamingHelperDrawInfo = this.initializeBeamDrawingInfo(h, direction)
        h.drawingInfos.set(direction, drawingInfo)
        var barCount: Double = com.omnifret.gplayer.model.ModelUtils.getIndex(h.shortestDuration) - (2.0).toDouble()
        var barDrawingShift: Double = this.applyBarShift(h, direction, drawingInfo, barCount)
        if (h.beats.length > 1)
        {
            if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)
            {
                var yNeededForHighestNote: Double = barDrawingShift + this.getFlagTopY(h.beatOfHighestNote, direction)
                var yGivenByCurrentValues: Double = drawingInfo.calcY(this.getBeatX(h.beatOfHighestNote, com.omnifret.gplayer.rendering.BeatXPosition.Stem))
                var diff: Double = yGivenByCurrentValues - yNeededForHighestNote
                if (diff > 0)
                {
                    drawingInfo.startY -= diff
                    drawingInfo.endY -= diff
                }
            }
            else 
            {
                var yNeededForLowestNote: Double = barDrawingShift + this.getFlagBottomY(h.beatOfLowestNote, direction)
                var yGivenByCurrentValues: Double = drawingInfo.calcY(this.getBeatX(h.beatOfLowestNote, com.omnifret.gplayer.rendering.BeatXPosition.Stem))
                var diff: Double = yNeededForLowestNote - yGivenByCurrentValues
                if (diff > 0)
                {
                    drawingInfo.startY += diff
                    drawingInfo.endY += diff
                }
            }
            var barSpacing: Double = 0.0
            if (h.restBeats.length > 0)
            {
                var scaleMod: Double = if(h.graceType != com.omnifret.gplayer.model.GraceType.None)  com.omnifret.gplayer.EngravingSettings.GraceScale else 1.0
                barSpacing = barCount * (this.beamSpacing + this.beamThickness) * scaleMod
            }
            for (b in h.restBeats)
            {
                if (b.isRest && b.index < h.beats[(h.beats.length - (1.0).toDouble()).toInt()].index)
                {
                    if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)
                    {
                        var yNeededForRest: Double = this.getBeatContainer(b)!!.getBoundingBoxTop() - barSpacing
                        var yGivenByCurrentValues: Double = drawingInfo.calcY(this.getBeatX(b, com.omnifret.gplayer.rendering.BeatXPosition.Stem))
                        var diff: Double = yGivenByCurrentValues - yNeededForRest
                        if (diff > 0)
                        {
                            drawingInfo.startY -= diff
                            drawingInfo.endY -= diff
                        }
                    }
                    else if (((direction as com.omnifret.gplayer.rendering.utils.BeamDirection)) == com.omnifret.gplayer.rendering.utils.BeamDirection.Down)
                    {
                        var yNeededForRest: Double = this.getBeatContainer(b)!!.getBoundingBoxBottom() + barSpacing
                        var yGivenByCurrentValues: Double = drawingInfo.calcY(this.getBeatX(b, com.omnifret.gplayer.rendering.BeatXPosition.Stem))
                        var diff: Double = yNeededForRest - yGivenByCurrentValues
                        if (diff > 0)
                        {
                            drawingInfo.startY += diff
                            drawingInfo.endY += diff
                        }
                    }
                }
            }
            if (h.slashBeats.length > 0)
            {
                for (b in h.slashBeats)
                {
                    var yGivenByCurrentValues: Double = drawingInfo.calcY(this.getBeatX(b, com.omnifret.gplayer.rendering.BeatXPosition.Stem))
                    var yNeededForSlash: Double = if(direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)  this.getFlagTopY(b, direction) else this.getFlagBottomY(b, direction)
                    var diff: Double = yNeededForSlash - yGivenByCurrentValues
                    if (diff > 0)
                    {
                        drawingInfo.startY += diff
                        drawingInfo.endY += diff
                    }
                }
            }
        }
        if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)
        {
            drawingInfo.startY = com.omnifret.gplayer.core.ecmaScript.Math.round(drawingInfo.startY)
            drawingInfo.endY = com.omnifret.gplayer.core.ecmaScript.Math.round(drawingInfo.endY)
        }
        else 
        {
            drawingInfo.startY = com.omnifret.gplayer.core.ecmaScript.Math.round(drawingInfo.startY)
            drawingInfo.endY = com.omnifret.gplayer.core.ecmaScript.Math.round(drawingInfo.endY)
        }
    }
    
    /**
     */
    protected open fun applyBarShift(h: com.omnifret.gplayer.rendering.utils.BeamingHelper, direction: com.omnifret.gplayer.rendering.utils.BeamDirection, drawingInfo: com.omnifret.gplayer.rendering.utils.BeamingHelperDrawInfo, barCount: Double): Double{
        var barDrawingShift: Double = 0.0
        var isRest: Boolean = h.isRestBeamHelper
        var scale: Double = if(h.graceType != com.omnifret.gplayer.model.GraceType.None)  com.omnifret.gplayer.EngravingSettings.GraceScale else 1.0
        if (barCount > 2 && !isRest)
        {
            var beamSpacing: Double = this.beamSpacing * scale
            var beamThickness: Double = this.beamThickness * scale
            var totalBarsHeight: Double = barCount * beamThickness + (barCount - (1.0).toDouble()) * beamSpacing
            if (direction == com.omnifret.gplayer.rendering.utils.BeamDirection.Up)
            {
                var bottomBarY: Double = drawingInfo.startY + (2.0).toDouble() * beamThickness + beamSpacing
                var barTopY: Double = bottomBarY - totalBarsHeight
                var diff: Double = drawingInfo.startY - barTopY
                if (diff > 0)
                {
                    barDrawingShift = diff * -1.0
                    drawingInfo.startY -= diff
                    drawingInfo.endY -= diff
                }
            }
            else 
            {
                var topBarY: Double = drawingInfo.startY - (2.0).toDouble() * beamThickness + beamSpacing
                var barBottomY: Double = topBarY + totalBarsHeight
                var diff: Double = barBottomY - drawingInfo.startY
                if (diff > 0)
                {
                    barDrawingShift = diff
                    drawingInfo.startY += diff
                    drawingInfo.endY += diff
                }
            }
        }
        return barDrawingShift
    }
    
    /**
     */
    protected open fun getMinLineOfBeat(_beat: com.omnifret.gplayer.model.Beat): Double{
        return 0.0
    }
    
    /**
     */
    protected open fun getMaxLineOfBeat(_beat: com.omnifret.gplayer.model.Beat): Double{
        return 0.0
    }
    
    /**
     */
    public abstract fun getNoteLine(note: com.omnifret.gplayer.model.Note): Double
    
    companion object{
        /**
         */
        @kotlin.jvm.JvmStatic
        protected fun paintSingleBar(canvas: com.omnifret.gplayer.platform.ICanvas, 
        x1: Double, 
        y1: Double, 
        x2: Double, 
        y2: Double, 
        size: Double): Unit{
            canvas.beginPath()
            canvas.moveTo(x1, y1)
            canvas.lineTo(x2, y2)
            canvas.lineTo(x2, y2 + size)
            canvas.lineTo(x1, y1 + size)
            canvas.closePath()
            canvas.fill()
        }
        
    }
    public constructor(renderer: com.omnifret.gplayer.rendering.ScoreRenderer, bar: com.omnifret.gplayer.model.Bar)
        : super(renderer, bar)
}

